  , mVoidTy(llvm::Type::getVoidTy(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
  , mLoopCond(nullptr)
  , mLoopEnd(nullptr)
{
}

llvm::AllocaInst*
EmitIR::getOrCreateAlloca(llvm::Type* ty, const std::string& name)
{
  auto iter = mSymtbl.find(name);
  if (iter != mSymtbl.end())
    return iter->second;
  auto& irb = *mCurIrb;
  auto alloca = irb.CreateAlloca(ty, nullptr, name);
  if (!name.empty())
    mSymtbl[name] = alloca;
  return alloca;
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kVoid:
        return mVoidTy;
      case Type::Spec::kInt:
        return mIntTy;
      default:
        ABORT();
    }
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    Type subt;
    subt.spec = type->spec;
    subt.qual = type->qual;
    subt.texp = type->texp->sub;
    std::vector<llvm::Type*> pty;
    for (auto&& paramType : p->params)
      pty.push_back(self(paramType));
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  if (auto p = type->texp->dcst<PointerType>()) {
    Type subt;
    subt.spec = type->spec;
    subt.qual = type->qual;
    subt.texp = type->texp->sub;
    return llvm::PointerType::get(self(&subt), 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    Type subt;
    subt.spec = type->spec;
    subt.qual = type->qual;
    subt.texp = type->texp->sub;
    return llvm::ArrayType::get(self(&subt), p->len);
  }

  return llvm::PointerType::get(mCtx, 0);
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);

  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);

  if (auto p = obj->dcst<ParenExpr>())
    return self(p);

  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);

  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);

  if (auto p = obj->dcst<CallExpr>())
    return self(p);

  if (auto p = obj->dcst<InitListExpr>())
    return self(p);

  if (auto p = obj->dcst<ImplicitInitExpr>())
    return self(p);

  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);

  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  if (auto p = decl->dcst<VarDecl>()) {
    if (p->type->texp == nullptr &&
        p->type->spec == Type::Spec::kInt &&
        p->any.is<llvm::GlobalVariable*>()) {
      return p->any.as<llvm::GlobalVariable*>();
    }
    if (p->any.is<llvm::AllocaInst*>())
      return p->any.as<llvm::AllocaInst*>();
    if (p->any.is<llvm::GlobalVariable*>())
      return p->any.as<llvm::GlobalVariable*>();
    ABORT();
  }
  if (auto p = decl->dcst<FunctionDecl>()) {
    auto func = llvm::dyn_cast_or_null<llvm::Function>(p->any.as<llvm::Value*>());
    if (func)
      return func;
    auto f = mMod.getFunction(decl->name);
    if (f)
      return f;
    auto fty = llvm::dyn_cast<llvm::FunctionType>(self(decl->type));
    return llvm::Function::Create(fty, llvm::GlobalVariable::ExternalLinkage,
                                  decl->name, mMod);
  }
  ABORT();
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return mCurIrb->CreateNeg(sub);
    case UnaryExpr::kNot:
      return mCurIrb->CreateNot(sub);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto lft = self(obj->lft);
  auto rht = self(obj->rht);
  switch (obj->op) {
    case BinaryExpr::kMul:
      return irb.CreateMul(lft, rht);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lft, rht);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lft, rht);
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lft, rht);
    case BinaryExpr::kSub:
      return irb.CreateSub(lft, rht);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lft, rht);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lft, rht);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lft, rht);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lft, rht);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lft, rht);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lft, rht);
    case BinaryExpr::kAnd:
    case BinaryExpr::kOr:
    case BinaryExpr::kAssign:
    case BinaryExpr::kComma:
    case BinaryExpr::kIndex:
      ABORT();
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto head = self(obj->head);
  auto fty = llvm::dyn_cast<llvm::FunctionType>(
    llvm::dyn_cast<llvm::PointerType>(head->getType())->getElementType());
  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args)
    args.push_back(self(arg));
  return mCurIrb->CreateCall(fty, head, args);
}

llvm::Value*
EmitIR::operator()(InitListExpr* obj)
{
  ABORT();
}

llvm::Value*
EmitIR::operator()(ImplicitInitExpr* obj)
{
  return llvm::Constant::getNullValue(self(obj->type));
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto sub = self(obj->sub);
  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue: {
      auto loadTy = self(obj->type);
      return mCurIrb->CreateLoad(loadTy, sub);
    }
    case ImplicitCastExpr::kNoOp:
      return sub;
    case ImplicitCastExpr::kIntegralCast:
      return mCurIrb->CreateIntCast(sub, self(obj->type), true);
    case ImplicitCastExpr::kArrayToPointerDecay:
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return sub;
    default:
      ABORT();
  }
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<NullStmt>())
    return self(p);

  if (auto p = obj->dcst<DeclStmt>())
    return self(p);

  if (auto p = obj->dcst<ExprStmt>())
    return self(p);

  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);

  if (auto p = obj->dcst<IfStmt>())
    return self(p);

  if (auto p = obj->dcst<WhileStmt>())
    return self(p);

  if (auto p = obj->dcst<BreakStmt>())
    return self(p);

  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);

  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(NullStmt* obj)
{
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls)
    self(decl);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    self(obj->expr);
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc) : nullptr;
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", mCurFunc);

  if (elseBb)
    irb.CreateCondBr(cond, thenBb, elseBb);
  else
    irb.CreateCondBr(cond, thenBb, endBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!thenBb->getTerminator())
    irb.CreateBr(endBb);

  if (elseBb) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!elseBb->getTerminator())
      irb.CreateBr(endBb);
  }

  irb.SetInsertPoint(endBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", mCurFunc);

  auto prevLoopCond = mLoopCond;
  auto prevLoopEnd = mLoopEnd;
  mLoopCond = condBb;
  mLoopEnd = endBb;

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);

  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  if (!bodyBb->getTerminator())
    irb.CreateBr(condBb);

  irb.SetInsertPoint(endBb);

  mLoopCond = prevLoopCond;
  mLoopEnd = prevLoopEnd;
}

void
EmitIR::operator()(BreakStmt* obj)
{
  mCurIrb->CreateBr(mLoopEnd);
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  mCurIrb->CreateBr(mLoopCond);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!obj->expr) {
    irb.CreateRetVoid();
  } else {
    auto retVal = self(obj->expr);
    irb.CreateRet(retVal);
  }
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  // 全局变量
  if (mCurFunc == nullptr) {
    auto ty = self(obj->type);
    llvm::Constant* initVal;
    if (obj->init)
      initVal = llvm::dyn_cast<llvm::Constant>(self(obj->init));
    else
      initVal = llvm::Constant::getNullValue(ty);
    auto gv = new llvm::GlobalVariable(
      mMod, ty, obj->type->qual.const_,
      llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    obj->any = gv;
    return;
  }

  // 局部变量
  auto ty = self(obj->type);
  auto alloca = getOrCreateAlloca(ty, obj->name);
  obj->any = alloca;
  if (obj->init) {
    auto initVal = self(obj->init);
    mCurIrb->CreateStore(initVal, alloca);
  }
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;

  mSymtbl.clear();

  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& entryIrb = *mCurIrb;

  // 处理函数参数
  for (auto&& arg : func->args()) {
    auto paramDecl = obj->params[arg.getArgNo()];
    auto alloca = entryIrb.CreateAlloca(arg.getType(), nullptr, paramDecl->name);
    entryIrb.CreateStore(&arg, alloca);
    paramDecl->any = alloca;
    mSymtbl[paramDecl->name] = alloca;
  }

  if (!fty->getReturnType()->isVoidTy()) {
    auto retval = entryIrb.CreateAlloca(fty->getReturnType(), nullptr, "retval");
    entryIrb.CreateStore(llvm::Constant::getNullValue(fty->getReturnType()), retval);
    mSymtbl["retval"] = retval;
  }

  mCurFunc = func;
  self(obj->body);
  auto& exitIrb = *mCurIrb;

  if (fty->getReturnType()->isVoidTy())
    exitIrb.CreateRetVoid();
  else
    exitIrb.CreateUnreachable();
}
